namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public string ImageUrl { get; set; } = string.Empty;
    public int TotalRatingPoints { get; set; }
    public int RatingCount { get; set; }
    public double AverageRating => RatingCount > 0 ? (double)TotalRatingPoints / RatingCount : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new()
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple, classic pizza with fresh mozzarella, tomatoes, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F (245°C).", "Roll out dough on a floured surface.", "Spread crushed tomatoes over the dough.", "Tear mozzarella and distribute evenly.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatingPoints = 18, RatingCount = 4
            },
            new()
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta made with eggs, pecorino, and guanciale.",
                Ingredients = ["Spaghetti", "Guanciale or pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted boiling water.", "Fry guanciale until crispy.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with guanciale off the heat.", "Add egg mixture and toss quickly to coat.", "Serve immediately with extra pecorino."],
                TotalRatingPoints = 14, RatingCount = 3
            },
            new()
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer 15 minutes.", "Stir in cream and garam masala.", "Add chicken pieces and simmer 10 more minutes."],
                TotalRatingPoints = 20, RatingCount = 4
            },
            new()
            {
                Id = 4, Title = "Vegetable Biryani", Category = "Indian",
                Description = "Fragrant basmati rice layered with spiced vegetables.",
                Ingredients = ["Basmati rice", "Mixed vegetables", "Onion", "Biryani masala", "Saffron", "Yogurt", "Ghee", "Mint leaves"],
                Steps = ["Soak rice for 30 minutes, then parboil.", "Fry sliced onions until golden.", "Cook vegetables with biryani masala and yogurt.", "Layer rice and vegetables in a heavy pot.", "Add saffron milk and ghee on top.", "Cover and cook on low heat for 20 minutes."],
                TotalRatingPoints = 9, RatingCount = 2
            },
            new()
            {
                Id = 5, Title = "Tacos al Pastor", Category = "Mexican",
                Description = "Marinated pork tacos with pineapple and cilantro.",
                Ingredients = ["Pork shoulder", "Dried chiles", "Pineapple", "Corn tortillas", "Cilantro", "Onion", "Lime"],
                Steps = ["Blend dried chiles with pineapple juice for marinade.", "Marinate sliced pork for at least 2 hours.", "Grill or pan-fry pork until caramelized.", "Grill pineapple slices.", "Warm tortillas on a skillet.", "Assemble tacos with pork, pineapple, onion, cilantro, and lime."],
                TotalRatingPoints = 15, RatingCount = 3
            },
            new()
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh avocado dip with lime, cilantro, and jalapeño.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve and pit avocados, scoop into a bowl.", "Mash to desired consistency.", "Stir in diced onion, tomato, and jalapeño.", "Add chopped cilantro and lime juice.", "Season with salt to taste.", "Serve immediately with tortilla chips."],
                TotalRatingPoints = 12, RatingCount = 3
            },
            new()
            {
                Id = 7, Title = "Beef Stir-Fry", Category = "Asian",
                Description = "Quick stir-fried beef with vegetables in a savory sauce.",
                Ingredients = ["Beef sirloin", "Soy sauce", "Sesame oil", "Broccoli", "Bell pepper", "Garlic", "Ginger", "Cornstarch"],
                Steps = ["Slice beef thinly and marinate in soy sauce and cornstarch.", "Heat oil in a wok over high heat.", "Stir-fry beef until browned, then remove.", "Stir-fry vegetables for 2–3 minutes.", "Return beef to the wok.", "Add sauce and toss until everything is coated."],
                TotalRatingPoints = 16, RatingCount = 4
            },
            new()
            {
                Id = 8, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Description = "Classic chewy cookies loaded with chocolate chips.",
                Ingredients = ["Butter", "Sugar", "Brown sugar", "Eggs", "Vanilla extract", "Flour", "Baking soda", "Chocolate chips"],
                Steps = ["Cream butter and sugars until fluffy.", "Beat in eggs and vanilla.", "Mix in flour, baking soda, and salt.", "Fold in chocolate chips.", "Scoop onto baking sheets.", "Bake at 375°F (190°C) for 9–11 minutes."],
                TotalRatingPoints = 20, RatingCount = 4
            },
            new()
            {
                Id = 9, Title = "Tiramisu", Category = "Desserts",
                Description = "Italian layered dessert with coffee-soaked ladyfingers and mascarpone.",
                Ingredients = ["Ladyfingers", "Espresso", "Mascarpone", "Eggs", "Sugar", "Cocoa powder", "Marsala wine"],
                Steps = ["Brew espresso and let it cool, then mix with Marsala.", "Separate eggs; beat yolks with sugar until thick.", "Fold mascarpone into yolk mixture.", "Whip egg whites to stiff peaks and fold in.", "Dip ladyfingers in coffee and layer in a dish.", "Spread mascarpone mixture over each layer and dust with cocoa."],
                TotalRatingPoints = 10, RatingCount = 2
            }
        ];
        _nextId = 10;
    }

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatingPoints += stars;
            recipe.RatingCount++;
        }
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted {submission.Category.ToLowerInvariant()} recipe.",
            Ingredients = submission.Ingredients
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = submission.Steps
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };
        _recipes.Add(recipe);
    }
}

