@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "<strong>@Submission!.Title</strong>" has been submitted.
        <a href="category/@Submission.Category">View @Submission.Category recipes</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" @bind-Value="Submission!.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                    <ValidationMessage For="() => Submission.Title" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" @bind-Value="Submission!.Category" class="form-select">
                        <option value="">-- Select a category --</option>
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat">@cat</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Submission.Category" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients (one per line)</label>
                    <InputTextArea id="ingredients" @bind-Value="Submission!.Ingredients" class="form-control" rows="6"
                                   placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" />
                    <ValidationMessage For="() => Submission.Ingredients" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps (one per line)</label>
                    <InputTextArea id="steps" @bind-Value="Submission!.Steps" class="form-control" rows="6"
                                   placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients." />
                    <ValidationMessage For="() => Submission.Steps" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                    @(isSubmitting ? "Submitting..." : "Submit Recipe")
                </button>
            </EditForm>
        </div>
    </div>
}

@code {
    private RecipeShare.Models.RecipeSubmission? Submission { get; set; }
    private bool submitted;
    private bool isSubmitting;

    protected override void OnInitialized() => Submission ??= new();

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        try
        {
            await Task.Delay(300); // simulate processing
            RecipeService.AddRecipe(Submission!);
            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

